{
  "verdict": "reject",
  "conceptual_groups": [
    {
      "id": "group-1",
      "summary": "Authority model is not a strict precedence chain and conflates operative authority with reference documents.",
      "severity": "major",
      "findings": [
        {
          "id": "f1",
          "description": "The draft says `Reports to: COO controller` but then lists `docs/v0/architecture.md` and `docs/VISION.md` under `Subordinate to`, which treats static documents as if they were live superiors. That is authority-unclear and conflicts with the repo rule that docs are reference evidence while runtime governance comes from the controller/memory engine.",
          "source_section": "<authority>"
        },
        {
          "id": "f2",
          "description": "The package never states what wins if the request, controller, contract, and referenced docs disagree. For a governance tool, missing precedence is a material gap, not a phrasing issue.",
          "source_section": "<authority> / Contract summary"
        }
      ],
      "redesign_guidance": "Rewrite authority as an explicit precedence chain. Separate operative authority from reference evidence. Example shape: controller/runtime contract first, request-scoped constraints next, reference docs as non-competing evidence."
    },
    {
      "id": "group-2",
      "summary": "Artifact lifecycle is not executable end-to-end because canonical outputs are described ambiguously and do not match required on-disk paths.",
      "severity": "blocking",
      "findings": [
        {
          "id": "f1",
          "description": "The self-check already reports four `MISSING_REQUIRED_OUTPUT` issues because `<outputs>` uses basename or slug-template references instead of the required canonical paths under `tools/agent-role-builder/role/`.",
          "source_section": "<outputs> / Self-check issues"
        },
        {
          "id": "f2",
          "description": "Step 2 writes drafts to `drafts/<slug>-...`, but the role never makes the promotion target explicit for each canonical artifact. The promotion path therefore requires inference.",
          "source_section": "<steps> Step 2 / <steps> Step 5 / <outputs>"
        },
        {
          "id": "f3",
          "description": "The contract summary `package_files` block omits the canonical directory prefix, which creates a second representation of the same artifacts and keeps the lifecycle inconsistent across markdown, contract, and filesystem.",
          "source_section": "Contract summary.package_files"
        },
        {
          "id": "f4",
          "description": "Completion criteria remain generic and do not define artifact expectations per terminal state. `Decision log updated (on freeze)` also leaves update/fix preservation mechanics undefined outside the happy path.",
          "source_section": "<completion> / <guardrails> / <steps> Step 5"
        }
      ],
      "redesign_guidance": "Use full tool-relative paths for every canonical artifact, distinguish canonical vs run-scoped artifacts consistently, and define completion separately for `frozen`, `pushback`, `blocked`, and `resume_required`. State exactly how decision history is preserved on update/fix."
    },
    {
      "id": "group-3",
      "summary": "The package hard-codes governance and runtime semantics that are either underspecified or not clearly authorized by the stated sources.",
      "severity": "major",
      "findings": [
        {
          "id": "f1",
          "description": "The role claims every governed run requires one live Codex leader and at least one live Codex+Claude reviewer pair, but the authority section does not identify a binding source for the leader-provider requirement. The pair requirement is grounded in architecture; the Codex-only leader requirement is not made authoritative here.",
          "source_section": "<role> / <inputs> / <guardrails>"
        },
        {
          "id": "f2",
          "description": "The contract summary bakes in `execution_mode: live-roster-v1`, `watchdog_timeout_seconds: 600`, `max_launch_attempts: 2`, and `allow_provider_fallback: false` as if they are stable role semantics. These read like request/runtime config, not durable role truth, and no authority chain is given for them.",
          "source_section": "Contract summary.runtime"
        },
        {
          "id": "f3",
          "description": "Step 4 says `Arbitrate after 2+ consecutive splits`, but it does not define actor, evidence, outcome state, or the approved limitation that arbitration is minor-only. That diverges from the repo's review-process architecture and risks inventing new board behavior.",
          "source_section": "<steps> Step 4 / Contract summary.governance"
        }
      ],
      "redesign_guidance": "Move request-specific runtime knobs into request/runtime config, not core role semantics. For board behavior, restate only approved mechanics from the governing review architecture and define arbitration mechanically: trigger, actor, evidence, severity limit, and terminal effect."
    },
    {
      "id": "group-4",
      "summary": "Scope boundaries are mostly clear, but the not-in-scope list contains duplicate semantics.",
      "severity": "minor",
      "findings": [
        {
          "id": "f1",
          "description": "`Application workflow creation` appears twice in `Not in scope`, once bare and once parenthetically clarified. That adds noise and weakens the exactness expected of a governed role.",
          "source_section": "<scope>"
        }
      ],
      "redesign_guidance": "Deduplicate the exclusion list and keep one canonical phrasing per out-of-scope concept."
    }
  ],
  "residual_risks": [
    "If runtime/provider specifics remain embedded in the role, future controller or roster changes will require unnecessary role rewrites and may cause false governance failures.",
    "If terminal-state predicates and artifact rules are not made mechanically testable, review cycles can continue to stall around freeze vs pushback vs resume_required."
  ],
  "strengths": [
    "The required XML-tagged structure is present and the tag set is explicitly enumerated in the self-check step.",
    "High-level ownership boundaries are directionally sound: tool creation is excluded, and the role stays focused on role-package governance.",
    "Context-gathering preconditions are sequenced sensibly, especially request validation, source verification, and baseline/resume loading."
  ]
}

